// Stage C.2 — canonical_json byte-exact port of cknf.ntp_trust.canonical_json.
//
// Golden vectors were generated by running the actual Python source
// `from cknf.ntp_trust import canonical_json, sha256_of_canonical_json`
// inside the CKNF venv on 2026-05-19. If you add a vector here, regenerate
// the corresponding JSON and SHA-256 by running the same Python on the same
// input — DO NOT hand-edit either field.

package canonicaljson

import (
	"crypto/sha256"
	"encoding/hex"
	"testing"
)

type goldenVector struct {
	name string
	in   any
	want string // exact Python canonical_json output
	hash string // sha256_of_canonical_json(in)
}

