func TestMarshal_GoldenVectors(t *testing.T) {
	for _, g := range goldens {
		t.Run(g.name, func(t *testing.T) {
			got, err := MarshalString(g.in)
			if err != nil {
				t.Fatalf("Marshal: %v", err)
			}
			if got != g.want {
				t.Errorf("byte-exact mismatch\n  want: %q\n  got:  %q", g.want, got)
			}
		})
	}
}

func TestSHA256Hex_GoldenVectors(t *testing.T) {
	for _, g := range goldens {
		t.Run(g.name, func(t *testing.T) {
			h, err := SHA256Hex(g.in)
			if err != nil {
				t.Fatalf("SHA256Hex: %v", err)
			}
			if h != g.hash {
				t.Errorf("hash mismatch\n  want: %s\n  got:  %s", g.hash, h)
			}
			expectedSum := sha256.Sum256([]byte(g.want))
			expectedHex := hex.EncodeToString(expectedSum[:])
			if expectedHex != g.hash {
				t.Errorf("test vector is self-inconsistent: hash %s does not match SHA-256 of %q (= %s)",
					g.hash, g.want, expectedHex)
			}
		})
	}
}

func TestMarshal_RejectsFloat32(t *testing.T) {
	if _, err := Marshal(float32(1.5)); err == nil {
		t.Error("expected error on float32 input")
	}
}

func TestMarshal_RejectsFloat64(t *testing.T) {
	if _, err := Marshal(float64(1.5)); err == nil {
		t.Error("expected error on float64 input")
	}
}

func TestMarshal_RejectsFloatInMap(t *testing.T) {
	in := map[string]any{"x": 1.0}
	if _, err := Marshal(in); err == nil {
		t.Error("expected error on map containing float")
	}
}

func TestMarshal_TypedStruct(t *testing.T) {
	type kv struct {
		B int `json:"b"`
		A int `json:"a"`
	}
	got, err := MarshalString(kv{B: 2, A: 1})
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}
	want := `{"a":1,"b":2}`
	if got != want {
		t.Errorf("typed struct\n  want: %s\n  got:  %s", want, got)
	}
}

func TestMarshal_DeterministicAcrossRuns(t *testing.T) {
	in := map[string]any{
		"z": []any{"end"},
		"a": 1,
		"m": map[string]any{"y": 2, "x": 1},
	}
	first, err := MarshalString(in)
	if err != nil {
		t.Fatalf("Marshal: %v", err)
	}
	for i := 0; i < 100; i++ {
		got, err := MarshalString(in)
		if err != nil {
			t.Fatalf("Marshal iter %d: %v", i, err)
		}
		if got != first {
			t.Fatalf("non-deterministic output at iter %d:\n  first: %q\n  got:   %q",
				i, first, got)
		}
	}
}
